var Aquired = new Array();

var Tooltips = new Array();
function stringReplaceAll( str, from, to )
{
    if ((typeof(str) != "string") || (typeof(from) != "string") || (typeof(str) != "string")) return str;
    var idx = str.indexOf( from );
    while ( idx > -1 ) {
        str = str.replace( from, to );
        idx = str.indexOf( from );
    }

    return str;
}
function techGenerateTooltipText(id)
{
	var tempString = new String();
	for(var i = 0; i < Tech[id].length; i++)
	{
		switch(i)
		{
			case 0:
			{
				if(Tech[id][i].length > 1)
				tempString += '<span class="techCategory">Category: '+Tech[id][i] + '<span/><br/>';
				break;
			}
			case 1:
			{
				if(Tech[id][i].length > 1)
				tempString += '<span class="techTitle">Title: '+Tech[id][i] + '<span/><br/>';
				break;
			}
			case 2:
			{
				if(Tech[id][i].length > 1)
				tempString += '<span class="techPrereq">Req: '+Tech[id][i] + '<span/><br/>';
				break;
			}
			case 3:
			{
				if(Tech[id][i].length > 1)
				tempString += '<span class="techProject">Projects: '+Tech[id][i] + '<span/><br/>';
				break;
			}
			case 4:
			{
				if(Tech[id][i].length > 1)
				tempString += '<span class="techSpy">Spy Op: '+Tech[id][i] + '<span/><br/>';
				break;
			}
			case 5:
			{
				if(Tech[id][i].length > 1)
				tempString += '<span class="techComponent">Component: '+Tech[id][i] + '<span/><br/>';
				break;
			}
			case 5:
			{
				if(Tech[id][i].length > 1)
				tempString += '<span class="techControlModel">Control Model: '+Tech[id][i] + '<span/><br/>';
				break;
			}
			default:
			{
				break;
			}
		}

	}
	return tempString;
}

function InitToolTips()
{
	for(var i = 0; i < Tech.length; i++)
	{
		Tooltips[i] = new YAHOO.widget.Tooltip("tt"+i, { context:stringReplaceAll(Tech[i][1]," ", ""), text:techGenerateTooltipText(i) } );
	}
}

function SetFilePrefix(ele, name)
{
	if(document.getElementById(stringReplaceAll(Tech[ele][1]," ", "")) == null)
	{
		alert(stringReplaceAll(Tech[ele][1]," ", ""));
	}
	var temp = document.getElementById(stringReplaceAll(Tech[ele][1]," ", "")).getElementsByTagName('img');

	temp[0].src = temp[0].src.replace('s_halogrey7hj', name);
	return;

}
function LightPrereqs(name)
{

	name = stringReplaceAll(name, " ", "");
	//check if we have the preqs
	for(var i = 0; i < Tech.length; i++)
	{
		if(stringReplaceAll(Tech[i][1], " ", "") == name)
		{
			var foundself = 0;
			//check if we are aquired
			for(var p = 0; p < Aquired.length; p++)
			{
				if(Aquired[p] == Tech[i][1])
				{
					foundself = 1;
					break;
				}

			}
			if(foundself == 0)
			{
				SetFilePrefix(i, 's_halored6pq');
			}
			//if we found the tech were looking for then check if we have it already
			var tempArray = Tech[i][2].split(', ');
			for(var y = 0; y < tempArray.length; y++)
			{
				var found = 0;
				for(var x = 0; x < Aquired.length; x++)
				{
					if(Aquired[x] == tempArray[y])
					{
						found = 1;
						break;
					}

				}
				if(found == 0)
				{
					//we have found one now light it up
					for(var l = 0; l < Tech.length; l++)
					{
						if(Tech[l][1] == tempArray[y])
						{
							//SetFilePrefix(l, 's_halored6pq');
							found = 1;
							LightPrereqs(tempArray[y]);
						}
					}

				}
				if(found == 0)
				{
					alert(tempArray[y]);
				}
			}
		}

	}
	return;
}
function LightAquired()
{
	for(var i = 0; i < Aquired.length; i++)
	{
		for(var l = 0; l < Tech.length; l++)
		{
			if(Tech[l][1] == Aquired[i])
			{
				SetFilePrefix(l, 's_halogreen2ec');
			}
		}
	}
	return;
}
function ResetPrereqLight()
{
	for(var i = 0; i < Tech.length; i++)
	{
		if(document.getElementById(stringReplaceAll(Tech[i][1]," ", "")) == null)
			alert(stringReplaceAll(Tech[i][1]," ", ""));
		var temp = document.getElementById(stringReplaceAll(Tech[i][1]," ", "")).getElementsByTagName('img');

		temp[0].src = temp[0].src.replace('s_halored6pq', 's_halogrey7hj');
	}
}

var Selected = "";
function SetTarget(name)
{
	for(var i = 0; i < Tech.length; i++)
	{
		if(stringReplaceAll(Tech[i][1], " ", "") == name)
		{
			Selected = Tech[i][1];
			return;
		}
	}
	alert("Could not find " + name + " Please Contact the Dev team");
}
